/**
 * This file is the injection point when we load the GdPicture web worker. We decided to run GdPicture in a dedicated Web Worker, because GdPicture WASM is strictly synchronous
 */
// Enable a dedicated worker environment

import { error } from '@pspdfkit/shared'

import GdPicture from '../GdPicture'

import type { GdPictureCommands as GdPictureInterface, Request, Response } from '../GdPictureTypes'

const gdpicture = new GdPicture()

// We alias `self` to be able to type it as `Worker` and not `Window`
const _self = self as unknown as Worker

// @ts-expect-error
_self.global = _self
// @ts-expect-error
_self.module = {}

_self.onmessage = async <K extends keyof GdPictureInterface>({
  data: request,
}: {
  data: Request<K>
}) => {
  let response: Response<K>
  let responseTransferList: ArrayBuffer[] | undefined

  try {
    // @ts-expect-error
    const result = (await gdpicture[request.action](...request.args)) as Response<K>['result']

    response = {
      id: request.id,
      result,
    }

    if (Array.isArray(result)) {
      const arrayBufferResults = (result as unknown[]).filter(
        i => i instanceof ArrayBuffer,
      ) as Array<ArrayBuffer>

      if (arrayBufferResults.length > 0) {
        responseTransferList = arrayBufferResults
      }
    }

    // When the result is an ArrayBuffer, we append it to the transfer list
    if (result instanceof ArrayBuffer) {
      responseTransferList = [result]
    }
  } catch (e) {
    const transferrableArgs = [...request.args].filter(
      arg => arg instanceof ArrayBuffer,
    ) as unknown as Array<ArrayBuffer>

    if (transferrableArgs.length > 0) {
      responseTransferList = transferrableArgs
    }

    //In a development build, we need access to the complete stack trace
    if (process.env.NODE_ENV == 'development') {
      // @ts-expect-error
      error('[PSPDFKit Internal Debug]', e.message, e.stack)
    }

    response = {
      id: request.id,
      error: e.message || e.toString(),
      callArgs: request.args as Parameters<GdPictureInterface[K]>,
    }
  }

  _self.postMessage(response, responseTransferList as Transferable[])
}
